-- ── Pandit & Puja feature ────────────────────────────────────────────────────
-- Tables: pujas (catalog) + pandits (directory, 10 cities)
-- All data world-readable; only service-role / admin can mutate.
-- Seed data sourced from migrations/1.json (delete that file after applying).

create table if not exists pujas (
  id              uuid        primary key default gen_random_uuid(),
  slug            text        unique not null,
  name_en         text        not null,
  name_sanskrit   text        not null,
  short_desc      text        not null,
  long_desc       text        not null,
  deity           text        not null,
  image_path      text        not null default '',  -- object path within 'pujas' Supabase Storage bucket
  primary_dosha   text,                              -- 'mangal'|'kaalsarp'|'sadesati'|'pitra'|'kemdruma'|'grahan'|'guruchandal'
  primary_planet  text,                              -- 'sun'|'moon'|'mars'|'mercury'|'jupiter'|'venus'|'saturn'|'rahu'|'ketu'
  intent_tags     text[]      not null default '{}',
  base_priority   int         not null default 5,
  duration_min    int,
  created_at      timestamptz not null default now()
);

create table if not exists pandits (
  id               uuid        primary key default gen_random_uuid(),
  name             text        not null,
  photo_url        text,
  city             text        not null,  -- slug: 'delhi'|'mumbai'|'bengaluru'|'chennai'|'hyderabad'|'kolkata'|'pune'|'ahmedabad'|'varanasi'|'prayagraj'
  phone            text        not null,
  whatsapp         text,
  years_experience int,
  languages        text[]      not null default '{}',
  specialisations  text[]      not null default '{}',  -- references pujas.slug values
  rating           numeric(2,1),
  verified         bool        not null default false,
  created_at       timestamptz not null default now()
);

create index if not exists pandits_city_idx on pandits(city);

alter table pujas   enable row level security;
alter table pandits enable row level security;

drop policy if exists "pujas_read_all"   on pujas;
drop policy if exists "pandits_read_all" on pandits;

create policy "pujas_read_all"   on pujas   for select using (true);
create policy "pandits_read_all" on pandits for select using (true);

