insert into pujas (slug, name_en, name_sanskrit, short_desc, long_desc, deity, primary_dosha, primary_planet, intent_tags, base_priority, duration_min) values
('ganapathi-homam',      'Ganapathi Homam',               'गणपति होमम्',            'Remove obstacles and invite auspicious beginnings.',                        'Ganapathi Homam is performed to seek blessings of Lord Ganesha before any important venture. The fire ritual clears obstacles and bestows wisdom, success, and divine grace upon the worshipper and their family.',                                                                                                    'Ganesha',                null,        null,       array['obstacles','career','wealth','education'],             65, 90),
('navagraha-shanti',     'Navagraha Shanti Homam',        'नवग्रह शान्ति होमम्',    'Pacify all nine planets to restore cosmic balance.',                        'Navagraha Shanti is a comprehensive fire ritual that appeases all nine celestial bodies simultaneously. Ideal for those experiencing general difficulties across multiple life areas or when multiple graha doshas exist in the chart.',                                                                               'Navagrahas',             null,        null,       array['health','protection','wealth','career'],               70, 180),
('maha-mrityunjaya-jaap','Maha Mrityunjaya Jaap',         'महामृत्युञ्जय जप',       'Conquer illness and fear through Shiva''s grace.',                          'The Maha Mrityunjaya mantra repeated 1,25,000 times dissolves karmic debts related to health and longevity, strengthens Moon energy, and provides divine protection against untimely misfortune.',                                                                                                                  'Shiva',                  null,        'moon',     array['health','longevity','protection'],                     60, 240),
('rudra-abhishek',       'Rudra Abhishek',                'रुद्राभिषेक',             'Sacred bathing of Shivalinga to cleanse karma.',                            'Rudra Abhishek involves ceremonial bathing of the Shivalinga with milk, honey, ghee, and sacred water while chanting the Sri Rudram. It purifies negative karma and brings peace to home and family.',                                                                                                                     'Shiva',                  null,        null,       array['health','protection','marriage','home'],               55, 120),
('mangal-shanti',        'Mangal Shanti Puja',            'मंगल शान्ति पूजा',       'Remedy Mangal Dosha and soften Mars afflictions.',                          'Mangal Shanti Puja pacifies planet Mars and nullifies Mangal Dosha. Strongly recommended before marriage when Mangal Dosha is detected, reducing delay in marriage, marital discord, and health issues.',                                                                                                               'Mangal (Mars)',           'mangal',    'mars',     array['marriage','health','protection'],                      80, 150),
('kaal-sarp-shanti',     'Kaal Sarp Shanti Puja',         'काल सर्प शान्ति पूजा',   'Release the serpent axis grip of Rahu-Ketu on your life.',                  'When all seven planets fall between Rahu and Ketu, Kaal Sarp Dosha forms. This powerful puja dissolves repeated failures, delays, and obstacles — and opens pathways to success.',                                                                                                                                   'Shiva / Nagdevata',      'kaalsarp',  'rahu',     array['career','protection','wealth','marriage'],             80, 240),
('sade-sati-shanti',     'Sade Sati / Shani Shanti Puja', 'साढ़े साती शान्ति पूजा', 'Ease Saturn''s 7.5-year trial and transform hardship into growth.',          'Sade Sati occurs when Saturn transits the Moon''s sign and the adjacent signs for 7.5 years. This puja pacifies Lord Shani, reduces losses and delays, and channels Saturn''s energy toward discipline and wisdom.',                                                                                                  'Shani (Saturn)',          'sadesati',  'saturn',   array['career','health','protection','wealth'],               80, 150),
('pitra-tarpan',         'Pitra Tarpan & Shraadh',        'पितृ तर्पण श्राद्ध',     'Offer water and gratitude to release ancestral debts.',                     'Pitra Tarpan is a sacred water offering ritual for deceased ancestors. Performed on Amavasya or Pitrupaksha, it satisfies the Pitrus, releases ancestral karma, and brings peace and prosperity to the family.',                                                                                                         'Pitru Devtas',           'pitra',     'sun',      array['moksha','protection','health'],                        70, 90),
('pitra-dosh-nivaran',   'Pitra Dosh Nivaran Puja',       'पितृ दोष निवारण पूजा',   'Comprehensive puja to fully remedy Pitra Dosha in your chart.',             'A full Pitra Dosh Nivaran puja includes Vishnu Puja, Brahmin bhojan, and specific mantras to appease the Sun and ancestors. Recommended when Pitra Dosha is detected with moderate to severe intensity.',                                                                                                          'Pitru Devtas / Vishnu',  'pitra',     'sun',      array['moksha','health','wealth','protection'],                75, 180),
('maha-lakshmi-puja',    'Maha Lakshmi Puja',             'महालक्ष्मी पूजा',         'Invite abundance and the blessings of the Goddess of Wealth.',              'Maha Lakshmi Puja attracts material prosperity, overcomes financial difficulties, and strengthens Venus in the chart. Beneficial for those in business, facing monetary stagnation, or seeking marital harmony.',                                                                                                   'Lakshmi',                null,        'venus',    array['wealth','marriage','home'],                            50, 90),
('saraswati-puja',       'Saraswati Puja',                'सरस्वती पूजा',            'Awaken intelligence, speech, and artistic mastery.',                        'Saraswati Puja strengthens Mercury in the chart, helps students excel, improves communication and creative expression. Ideal for those in education, writing, music, or teaching.',                                                                                                                                        'Saraswati',              null,        'mercury',  array['education','career','obstacles'],                      45, 60),
('durga-saptashati',     'Durga Saptashati Path',         'दुर्गा सप्तशती पाठ',     '700 verses of divine feminine power for protection and victory.',           'The Durga Saptashati is a recitation of 700 shlokas describing Goddess Durga''s victory over evil. Performed for protection from enemies, overcoming serious obstacles, and invoking the divine feminine.',                                                                                                             'Durga',                  null,        null,       array['protection','health','obstacles','career'],            55, 180),
('sudarshana-homam',     'Sudarshana Homam',              'सुदर्शन होमम्',           'Invoke Vishnu''s divine disc to destroy negative forces.',                  'Sudarshana Homam is a powerful fire ritual invoking Lord Vishnu''s Sudarshana Chakra. It protects from evil eye, black magic, and enemies, and strengthens the Sun for those in authority roles.',                                                                                                              'Vishnu / Sudarshana',    null,        'sun',      array['protection','health','career'],                        50, 150),
('chandi-homam',         'Chandi Homam',                  'चण्डी होमम्',             'An intensive fire ritual to the fierce goddess Chandi.',                    'Chandi Homam involves 64 types of offerings and is one of the most powerful fire rituals in the Vedic tradition. Performed to overcome grave difficulties, break karmic cycles, and invoke divine intervention.',                                                                                                        'Chandi (Durga)',         null,        null,       array['protection','wealth','obstacles','health'],            55, 300),
('ayushya-homam',        'Ayushya Homam',                 'आयुष्य होमम्',            'A life-extending ritual for health, longevity, and safe childbirth.',      'Ayushya Homam is dedicated to Lord Shiva and the presiding deity of longevity. Performed on birthdays or before childbirth, it is also recommended for those with weak Moon or recurring health challenges.',                                                                                                      'Shiva / Ayushya Devata', null,        'moon',     array['health','longevity','childbirth'],                     50, 120),
('vastu-shanti',         'Vastu Shanti Puja',             'वास्तु शान्ति पूजा',     'Harmonise your home or workspace with the five elements.',                  'Vastu Shanti Puja is performed before or after moving into a new space to purify Vastu defects, appease directional deities, correct elemental imbalances, and ensure peace and prosperity for inhabitants.',                                                                                                    'Vastu Purusha',          null,        null,       array['home','property','protection'],                        50, 120),
('griha-pravesh',        'Griha Pravesh Puja',            'गृहप्रवेश पूजा',          'Consecrate your new home with Vedic rites before the first entry.',        'Griha Pravesh is the sacred housewarming ceremony performed on an auspicious muhurta. It involves Vastu puja, Ganapathi puja, havan, and sprinkling of holy water, filling the home with divine blessings.',                                                                                                     'All deities',            null,        null,       array['home','property','protection'],                        45, 150),
('surya-aradhana',       'Surya Aradhana',                'सूर्य आराधना',            'Worship the Sun god for authority, health, and career success.',            'Surya Aradhana strengthens the Sun through water offerings, Aditya Hridayam recitation, and Sun mantras. Beneficial for leaders, government employees, and those with weak Sun facing issues with authority.',                                                                                                        'Surya',                  null,        'sun',      array['career','health','education'],                         45, 60),
('chandra-shanti',       'Chandra Shanti Puja',           'चन्द्र शान्ति पूजा',     'Calm the mind and nourish the Moon for emotional well-being.',              'Chandra Shanti Puja strengthens the Moon in the birth chart. A weak Moon causes emotional instability, depression, poor memory, and relationship difficulties. White flowers and silver items are offered to Lord Chandra.',                                                                                       'Chandra (Moon)',         null,        'moon',     array['health','marriage','protection'],                      45, 90),
('budha-shanti',         'Budha Graha Shanti',            'बुध ग्रह शान्ति',         'Strengthen Mercury for clear thinking, speech, and commerce.',              'Budha Shanti puja pacifies and strengthens Mercury. Ideal for students, writers, traders, and those in communication roles experiencing confusion, speech difficulties, or poor academic performance.',                                                                                                                'Budha (Mercury)',        null,        'mercury',  array['education','career','wealth'],                         45, 90),
('guru-puja',            'Brihaspati / Guru Puja',        'बृहस्पति गुरु पूजा',     'Invoke Jupiter''s wisdom, grace, and divine knowledge.',                    'Guru Puja strengthens the most benefic planet in Vedic astrology. A strong Jupiter brings children, marital happiness, wisdom, and wealth. Recommended for those with delays in marriage, childlessness, or financial stagnation.',                                                                                 'Brihaspati (Jupiter)',   null,        'jupiter',  array['wealth','education','marriage','childbirth'],          45, 90),
('shukra-puja',          'Shukra Graha Puja',             'शुक्र ग्रह पूजा',         'Attract love, beauty, and material luxury through Venus worship.',          'Shukra Puja enhances Venus in the birth chart. A strong Venus brings marital bliss, creative success, artistic talents, and material comforts. Beneficial for relationship difficulties caused by a weak Venus.',                                                                                                   'Shukra (Venus)',         null,        'venus',    array['marriage','wealth','career'],                          45, 90),
('rahu-shanti',          'Rahu Graha Shanti',             'राहु ग्रह शान्ति',         'Pacify the shadow planet Rahu for clarity and karmic relief.',              'Rahu Shanti puja mitigates the malefic effects of Rahu — confusion, addiction, sudden reversals. Rahu-specific mantras, incense, and black sesame offerings bring clarity, stability, and relief from chaotic Rahu energy.',                                                                                    'Rahu',                   null,        'rahu',     array['career','protection','health'],                        50, 120),
('ketu-shanti',          'Ketu Graha Shanti',             'केतु ग्रह शान्ति',         'Quieten Ketu''s detachment for spiritual peace and grounding.',             'Ketu Shanti puja calms the influence of Ketu, the south node of the Moon. An afflicted Ketu causes mysterious illnesses and unexplained losses. This puja helps ground spiritual energy and support moksha.',                                                                                                   'Ketu',                   null,        'ketu',     array['moksha','protection','health'],                        50, 120),
('hanuman-puja',         'Hanuman Puja & Chalisa',        'हनुमान पूजा',             'Call on Hanuman''s strength for courage and protection from evil.',         'Hanuman Puja with Chalisa recitation is among the most popular Vedic remedies. Hanuman is the deity of Mars energy — strength, courage, and devotion. This puja removes fear, wards off evil eye, and is recommended on Tuesdays.',                                                                                   'Hanuman',                null,        'mars',     array['protection','health','obstacles','career'],            55, 60),
('satya-narayan-katha',  'Satya Narayan Katha',           'सत्यनारायण कथा',         'A beloved Vishnu puja for family harmony and fulfilling wishes.',           'Satya Narayan Katha is traditionally performed on Purnima to express gratitude and seek Lord Vishnu''s blessings for family well-being, fulfilment of desires, success in ventures, and as thanksgiving for boons received.',                                                                                    'Satya Narayan (Vishnu)', null,        null,       array['wealth','home','protection','health'],                 50, 120),
('vishnu-sahasranama',   'Vishnu Sahasranama Path',       'विष्णु सहस्रनाम पाठ',    'Chant 1000 names of Lord Vishnu for cosmic protection and moksha.',         'The Vishnu Sahasranama is a sequence of 1000 names of Lord Vishnu from the Mahabharata. Regular recitation protects from all fears, removes sins, and bestows health, wealth, and liberation.',                                                                                                          'Vishnu',                 null,        null,       array['protection','moksha','health'],                        50, 90),
('grahan-dosh-nivaran',  'Grahan Dosh Nivaran Puja',      'ग्रहण दोष निवारण पूजा', 'Remedy eclipse-related doshas that affect health and clarity.',              'Grahan Dosha occurs when the Sun or Moon is conjunct Rahu or Ketu in the birth chart, causing confusion and health issues. This puja performs specific mantras for both the eclipsed luminary and the shadow planets.',                                                                                      'Surya / Chandra / Rahu-Ketu','grahan',null,       array['health','protection','career'],                        75, 150),
('guru-chandal-shanti',  'Guru Chandal Dosh Shanti',      'गुरु चाण्डाल दोष शान्ति','Purify Jupiter when afflicted by Rahu for wisdom and ethics.',              'Guru Chandal Dosha forms when Jupiter is conjunct or aspected by Rahu, causing poor judgment and difficulties with teachers. This puja performs Guru Puja and Rahu Shanti together to restore Jupiter''s purity.',                                                                                          'Brihaspati / Rahu',     'guruchandal','jupiter',  array['education','career','protection','wealth'],            75, 180),
('kemdruma-shanti',      'Kemdruma Dosh Nivaran',         'केमद्रुम दोष निवारण',    'Remedy the isolated Moon dosha for emotional security.',                    'Kemdruma Dosha arises when the Moon has no planet in adjacent houses, leaving it isolated and weakened. This causes emotional insecurity and relationship difficulties. White flowers, pearl offerings, and Chandra mantras restore the Moon.',                                                                  'Chandra (Moon)',         'kemdruma',  'moon',     array['health','marriage','protection'],                      75, 120),
('mahalakshmi-yagna',    'Maha Lakshmi Yagna',            'महालक्ष्मी यज्ञ',         'An intensive prosperity fire ritual with 64 types of offerings.',           'Maha Lakshmi Yagna is a large-scale fire ritual with 64 types of offerings including rare herbs, lotus flowers, ghee, and saffron. Performed with multiple priests, it powerfully activates Venus, removes financial blockages, and invites lasting prosperity.',                                          'Maha Lakshmi',           null,        'venus',    array['wealth','career','home'],                              55, 360)
on conflict (slug) do update set
  name_en = excluded.name_en, name_sanskrit = excluded.name_sanskrit,
  short_desc = excluded.short_desc, long_desc = excluded.long_desc,
  deity = excluded.deity, primary_dosha = excluded.primary_dosha,
  primary_planet = excluded.primary_planet, intent_tags = excluded.intent_tags,
  base_priority = excluded.base_priority, duration_min = excluded.duration_min;

